#include <omp.h>
#include <stdio.h>
#include <stdlib.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

// Forward declarations of the kernel functions
void lud_diagonal_omp(float *m, int matrix_dim, int offset);
void lud_perimeter_omp(float *m, int matrix_dim, int offset);
void lud_internal_omp(float *m, int matrix_dim, int offset);

// The main OpenMP kernel function
void lud_omp(float *m, int matrix_dim) {
    int i = 0;
    int num_threads = omp_get_max_threads();

    // Outer loop for blocks
    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        // lud_diagonal
        // This kernel operates on a single block and doesn't have explicit parallelism
        // that can be directly mapped to OpenMP threads in a loop.
        // It's a sequential computation within a block.
        lud_diagonal_omp(m, matrix_dim, i);

        // lud_perimeter
        // This kernel processes multiple blocks in parallel.
        // The original CUDA code uses `BLOCK_SIZE * 2` threads for `BLOCK_SIZE` blocks.
        // We can parallelize the loop over blocks.
        lud_perimeter_omp(m, matrix_dim, i);

        // lud_internal
        // This kernel also processes multiple blocks in parallel.
        // The original CUDA code uses `BLOCK_SIZE x BLOCK_SIZE` threads for
        // `(matrix_dim-i)/BLOCK_SIZE-1` x `(matrix_dim-i)/BLOCK_SIZE-1` blocks.
        // We can parallelize the grid of blocks.
        lud_internal_omp(m, matrix_dim, i);
    }

    // Handle the last block
    lud_diagonal_omp(m, matrix_dim, i);
}

// OpenMP version of lud_diagonal
void lud_diagonal_omp(float *m, int matrix_dim, int offset) {
    float shadow[BLOCK_SIZE][BLOCK_SIZE];
    int i, j;
    int array_offset;

    // Copy diagonal block to shared memory (shadow)
    // This part is sequential in OpenMP as it's a single block operation.
    for (i = 0; i < BLOCK_SIZE; i++) {
        array_offset = offset * matrix_dim + offset + i * matrix_dim;
        for (j = 0; j < BLOCK_SIZE; j++) {
            shadow[j][i] = m[array_offset + j];
        }
    }

    // Perform LU decomposition on the shadow matrix
    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        for (j = 0; j < i; j++) {
            shadow[i + 1][i] -= shadow[i + 1][j] * shadow[j][i];
        }
        shadow[i + 1][i] /= shadow[i][i];
    }

    // Write back the modified diagonal block to global memory
    for (i = 1; i < BLOCK_SIZE; i++) {
        array_offset = (offset + i) * matrix_dim + offset;
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[array_offset + j] = shadow[i][j];
        }
    }
}

// OpenMP version of lud_perimeter
void lud_perimeter_omp(float *m, int matrix_dim, int offset) {
    float dia[BLOCK_SIZE][BLOCK_SIZE];
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];
    int i, j, array_offset, idx;

    // Parallelize the computation over the blocks that form the perimeter
    // The original CUDA kernel uses `BLOCK_SIZE * 2` threads.
    // We can parallelize the loop over the blocks that need perimeter computation.
    // The number of such blocks is `(matrix_dim - offset) / BLOCK_SIZE - 1`.
    int num_perimeter_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;

    #pragma omp parallel for default(none) shared(m, matrix_dim, offset, BLOCK_SIZE, num_perimeter_blocks, dia, peri_row, peri_col) private(i, j, array_offset, idx)
    for (int block_idx = 0; block_idx < num_perimeter_blocks; ++block_idx) {
        // Copy diagonal elements to dia
        for (i = 0; i < BLOCK_SIZE; i++) {
            array_offset = (offset + i) * matrix_dim + offset + block_idx * BLOCK_SIZE;
            for (j = 0; j < BLOCK_SIZE; j++) {
                dia[i][j] = m[array_offset + j];
            }
        }

        // Copy perimeter row elements to peri_row
        for (i = 0; i < BLOCK_SIZE; i++) {
            array_offset = (offset + i) * matrix_dim + offset + (block_idx + 1) * BLOCK_SIZE;
            for (j = 0; j < BLOCK_SIZE; j++) {
                peri_row[i][j] = m[array_offset + j];
            }
        }

        // Copy perimeter column elements to peri_col
        for (i = 0; i < BLOCK_SIZE; i++) {
            array_offset = (offset + block_idx + 1) * BLOCK_SIZE * matrix_dim + offset + i * matrix_dim;
            for (j = 0; j < BLOCK_SIZE; j++) {
                peri_col[i][j] = m[array_offset + j];
            }
        }

        // Perform computations for peri_row
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (j = 0; j < i; j++) {
                peri_row[i][j] -= dia[i][j] * peri_row[j][j];
            }
        }

        // Perform computations for peri_col
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < i; j++) {
                peri_col[j][i] -= peri_col[j][j] * dia[j][i];
            }
            peri_col[j][i] /= dia[i][i];
        }

        // Write back modified peri_row
        for (i = 1; i < BLOCK_SIZE; i++) {
            array_offset = (offset + i) * matrix_dim + offset + (block_idx + 1) * BLOCK_SIZE;
            for (j = 0; j < BLOCK_SIZE; j++) {
                m[array_offset + j] = peri_row[i][j];
            }
        }

        // Write back modified peri_col
        for (i = 0; i < BLOCK_SIZE; i++) {
            array_offset = (offset + block_idx + 1) * BLOCK_SIZE * matrix_dim + offset + i * matrix_dim;
            for (j = 0; j < BLOCK_SIZE; j++) {
                m[array_offset + j] = peri_col[i][j];
            }
        }
    }
}

// OpenMP version of lud_internal
void lud_internal_omp(float *m, int matrix_dim, int offset) {
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];
    int i, j, array_offset;

    int num_blocks_per_dim = (matrix_dim - offset) / BLOCK_SIZE - 1;

    // Parallelize over the grid of internal blocks
    #pragma omp parallel for default(none) shared(m, matrix_dim, offset, BLOCK_SIZE, num_blocks_per_dim, peri_row, peri_col) private(i, j, array_offset)
    for (int block_y = 0; block_y < num_blocks_per_dim; ++block_y) {
        for (int block_x = 0; block_x < num_blocks_per_dim; ++block_x) {
            // Copy perimeter row elements to peri_row
            for (i = 0; i < BLOCK_SIZE; i++) {
                array_offset = (offset + i) * matrix_dim + offset + (block_x + 1) * BLOCK_SIZE;
                for (j = 0; j < BLOCK_SIZE; j++) {
                    peri_row[i][j] = m[array_offset + j];
                }
            }

            // Copy perimeter column elements to peri_col
            for (i = 0; i < BLOCK_SIZE; i++) {
                array_offset = (offset + (block_y + 1) * BLOCK_SIZE) * matrix_dim + offset + i * matrix_dim;
                for (j = 0; j < BLOCK_SIZE; j++) {
                    peri_col[i][j] = m[array_offset + j];
                }
            }

            // Compute the sum and update the internal block
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    float sum = 0;
                    for (int k = 0; k < BLOCK_SIZE; k++) {
                        sum += peri_col[i][k] * peri_row[k][j];
                    }
                    array_offset = (offset + (block_y + 1) * BLOCK_SIZE + i) * matrix_dim + offset + (block_x + 1) * BLOCK_SIZE + j;
                    m[array_offset] -= sum;
                }
            }
        }
    }
}
